import { forwardRef, type ReactNode } from "react";
import { clsx } from "clsx";
import { _BaseLink, type BaseLinkProps } from "./_BaseLink";
import { _BaseIcon } from "../Icon/_BaseIcon";
import { Text, type TextVariant } from "../Text";
import * as styles from "./Link.css";
import { DEFAULT_LINK_COLOR, DEFAULT_LINK_SIZE } from "./Link.config";
import type { LinkColor, LinkSize } from "./Link.config";

/**
 * Maps link size to the appropriate text variant.
 */
const TEXT_VARIANT_MAP: Record<LinkSize, TextVariant> = {
  sm: "link.sm.default",
  md: "link.base.default",
};

interface LinkCustomProps {
  /**
   * The size of the link text.
   * @default 'md'
   */
  size?: LinkSize;

  /**
   * Color theme for the link.
   * @default 'neutral'
   */
  color?: LinkColor;

  /**
   * Icon to display before the link text.
   * Typically used for back navigation or similar patterns.
   */
  iconStart?: ReactNode;

  /**
   * Icon to display after the link text.
   * Commonly used for external link indicators.
   */
  iconEnd?: ReactNode;

  /**
   * The content to display inside the link.
   */
  children: ReactNode;
}

/**
 * Props for the Link component.
 */
export interface LinkProps
  extends Omit<BaseLinkProps, keyof LinkCustomProps>, LinkCustomProps {}

/**
 * A styled link component for navigating to other pages or URLs.
 *
 * @example
 * // Basic link
 * <Link href="/about">About</Link>
 *
 * // With icons
 * <Link href="/back" iconStart={<ChevronLeftIcon />}>Back</Link>
 * <Link href="https://external.com" iconEnd={<ExternalLinkIcon />}>Visit site</Link>
 *
 * // Full page navigation
 * <Link href="/legacy" fullPageNavigation>Legacy Page</Link>
 *
 * // Small size
 * <Link href="/settings" size="sm">Settings</Link>
 */
export const Link = forwardRef<HTMLAnchorElement, LinkProps>(
  (
    {
      size = DEFAULT_LINK_SIZE,
      color = DEFAULT_LINK_COLOR,
      iconStart,
      iconEnd,
      className,
      children,
      ...props
    },
    ref
  ) => {
    return (
      <_BaseLink
        ref={ref}
        className={clsx(styles.link({ color }), className)}
        {...props}
      >
        {iconStart && (
          <_BaseIcon size={16} aria-hidden="true">
            {iconStart}
          </_BaseIcon>
        )}
        <Text variant={TEXT_VARIANT_MAP[size]}>
          <span>{children}</span>
        </Text>
        {iconEnd && (
          <_BaseIcon size={16} aria-hidden="true">
            {iconEnd}
          </_BaseIcon>
        )}
      </_BaseLink>
    );
  }
);

Link.displayName = "Link";
